    61→    if (fp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
    62→    {
    63→        if (sm >= 120)
    64→        {
    65→            return tkc::CutlassGemmConfig(tkc::CutlassTileConfigSM120::CtaShape128x128x256B,
    66→                tkc::MainloopScheduleType::AUTO, tkc::EpilogueScheduleType::AUTO,
    67→                tkc::ClusterShape::ClusterShape_1x1x1);
    68→        }
    69→        else if (sm == 103)
    70→        {
    71→            return tkc::CutlassGemmConfig(tkc::CutlassTileConfigSM100::CtaShape128x256x256B,
    72→                tkc::MainloopScheduleType::AUTO, tkc::EpilogueScheduleType::AUTO,
    73→                tkc::ClusterShape::ClusterShape_1x1x1);
    74→        }
    75→        else
    76→        {
    77→            return tkc::CutlassGemmConfig(tkc::CutlassTileConfigSM100::CtaShape128x256x128B,
    78→                tkc::MainloopScheduleType::AUTO, tkc::EpilogueScheduleType::AUTO,
