    80→        }
    81→    }
    82→    else if (fp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
    83→    {
    84→        return tkc::CutlassGemmConfig(tkc::CutlassTileConfigSM100::CtaShape128x256x256B,
